options.styles:
.pulse-container {
  width: 100%;
  height: 100%;
  background-image: url('data:image/svg+xml;base64,');
  background-size: cover;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  position: relative;
  color: #00d3ff;
}
.pulse-label {
  font-size: 1em;
  opacity: 0.7;
  margin-bottom: 5px;
}
.pulse-value {
  font-size: 3em;
  font-weight: bold;
  text-shadow: 0 0 10px rgba(0, 211, 255, 0.5);
}
.pulse-sparkline {
  position: absolute;
  bottom: 0;
  left: 0;
  width: 100%;
  height: 40%;
  opacity: 0.4;
}
#pulse-sparkline-canvas {
  width: 100%;
  height: 100%;
}

options.onRender:
const canvas = document.getElementById('pulse-sparkline-canvas');
if (canvas && data.length > 0) {
  const ctx = canvas.getContext('2d');
  const width = canvas.offsetWidth;
  const height = canvas.offsetHeight;
  canvas.width = width;
  canvas.height = height;

  // Business Text v6 passes 'data' which contains the rows directly when everyRow is false
  // We need to find the series values. In Business Text, 'data' is the joined rows.
  const values = data.map(row => row.A).filter(v => v !== null && !isNaN(v));

  ctx.clearRect(0, 0, width, height);
  if (values.length > 1) {
    ctx.beginPath();
    ctx.strokeStyle = '#00d3ff';
    ctx.lineWidth = 2;

    const max = Math.max(...values);
    const min = Math.min(...values);
    const range = max - min || 1;

    values.forEach((v, i) => {
      const x = (i / (values.length - 1)) * width;
      const y = height - ((v - min) / range) * height;
      if (i === 0) ctx.moveTo(x, y);
      else ctx.lineTo(x, y);
    });
    ctx.stroke();

    ctx.lineTo(width, height);
    ctx.lineTo(0, height);
    ctx.closePath();
    ctx.fillStyle = 'rgba(0, 211, 255, 0.1)';
    ctx.fill();
  }
}

